  "steps": [
    {
      "description": "Convert date and price columns to proper types and sort chronologically",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>%\n  mutate(\n    Date = lubridate::ymd(Date),\n    Close = as.numeric(gsub(\"[^0-9.-]\", \"\", Close)),\n    MA30 = as.numeric(gsub(\"[^0-9.-]\", \"\", MA30))\n  ) %>%\n  arrange(Date)",
      "considerations": "Ensures numeric calculations work and that lag() refers to the previous calendar day.",
      "status": "pending"
    },
    {
      "description": "Create the trend‑following signal using yesterday's data (removes look‑ahead bias)",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>%\n  mutate(Signal = ifelse(lag(Close) > lag(MA30), 1, 0)) %>%\n  tidyr::replace_na(list(Signal = 0))",
      "considerations": "Signal is 1 when yesterday's close was above yesterday's MA30, otherwise 0.",
      "status": "pending"
    },
    {
      "description": "Compute daily price return and flag days when the position changes (to apply transaction cost)",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>%\n  mutate(\n    Daily_Return = (Close / lag(Close)) - 1,\n    Daily_Return = tidyr::replace_na(Daily_Return, 0),\n    Trade_Flag = (Signal != lag(Signal, default = 0))\n  )",
      "considerations": "Trade_Flag = TRUE on days we flip from flat to long or vice‑versa.",
      "status": "pending"
    },
    {
      "description": "Calculate strategy return with a simple round‑trip transaction cost (0.1% per trade)",
      "r_code": "tc_per_trade <- 0.001  # 0.1% cost\nbitcoin_daily_5y <- bitcoin_daily_5y %>%\n  mutate(\n    Strategy_Return = lag(Signal) * Daily_Return - as.numeric(Trade_Flag) * tc_per_trade,\n    Strategy_Return = tidyr::replace_na(Strategy_Return, 0)\n  )",
      "considerations": "We use lag(Signal) so the position decided yesterday is applied today.",
      "status": "pending"
    },
    {
      "description": "Compute cumulative profit of the strategy",
      "r_code": "bitcoin_daily_5y <- bitcoin_daily_5y %>%\n  mutate(Cum_Profit = cumprod(1 + Strategy_Return) - 1)",
      "considerations": "Cum_Profit starts at 0 (i.e., $1 initial capital).",
      "status": "pending"
    },
    {
      "description": "Derive overall performance metrics (total, annualized return, volatility, Sharpe, max drawdown)",
      "r_code": "local({\n  n_days <- nrow(bitcoin_daily_5y)\n  years <- n_days / 365.25\n  total_ret <- tail(bitcoin_daily_5y$Cum_Profit, 1)\n  ann_ret <- (1 + total_ret)^(1/years) - 1\n  ann_vol <- sd(bitcoin_daily_5y$Strategy_Return, na.rm = TRUE) * sqrt(365.25)\n  sharpe <- ifelse(ann_vol == 0, NA, ann_ret / ann_vol)  # risk‑free rate = 0\n  # max drawdown\n  cum_max <- cummax(1 + bitcoin_daily_5y$Cum_Profit)\n  drawdowns <- (1 + bitcoin_daily_5y$Cum_Profit) / cum_max - 1\n  max_dd <- min(drawdowns, na.rm = TRUE)\n  overall_metrics <- data.frame(\n    Total_Return = total_ret,\n    Annualized_Return = ann_ret,\n    Annualized_Volatility = ann_vol,\n    Sharpe_Ratio = sharpe,\n    Max_Drawdown = max_dd\n  )\n  assign(\"overall_metrics\", overall_metrics, envir = .GlobalEnv)\n})",
      "considerations": "All calculations are done in a local block; only the final data frame `overall_metrics` persists.",
      "status": "pending"
    },
    {
      "description": "Separate performance during up‑trend (Close > MA30) and down‑trend (Close < MA30) periods",
      "r_code": "local({\n  uptrend <- bitcoin_daily_5y %>% filter(Close > MA30)\n  downtrend <- bitcoin_daily_5y %>% filter(Close < MA30)\n  up_metrics <- data.frame(\n    Period = \"Uptrend\",\n    Avg_Daily_Return = mean(uptrend$Strategy_Return, na.rm = TRUE),\n    Cum_Return = tail(uptrend$Cum_Profit, 1) - head(uptrend$Cum_Profit, 1)\n  )\n  down_metrics <- data.frame(\n    Period = \"Downtrend\",\n    Avg_Daily_Return = mean(downtrend$Strategy_Return, na.rm = TRUE),\n    Cum_Return = tail(downtrend$Cum_Profit, 1) - head(downtrend$Cum_Profit, 1)\n  )\n  trend_metrics <- dplyr::bind_rows(up_metrics, down_metrics)\n  assign(\"trend_metrics\", trend_metrics, envir = .GlobalEnv)\n})",
      "considerations": "Provides average daily strategy return and cumulative profit change for each market regime.",
      "status": "pending"
    },
    {
      "description": "Combine overall and regime‑specific metrics into a single summary table",
      "r_code": "performance_summary <- list(\n  Overall = overall_metrics,\n  Regime = trend_metrics\n)\n# Print the summary for the user\nprint(performance_summary)",
      "considerations": "The list `performance_summary` is the final object the user asked for.",
      "status": "pending"
    },
    {
      "description": "Cleanup all intermediate objects that are not part of the final results",
      "r_code": "rm(tc_per_trade, uptrend, downtrend, up_metrics, down_metrics, trend_metrics, overall_metrics, n_days, years, total_ret, ann_ret, ann_vol, sharpe, cum_max, drawdowns, max_dd, uptrend, downtrend)",
      "considerations": "Only `bitcoin_daily_5y` and `performance_summary` remain in the global environment.",
      "status": "pending"
    }
  ]
}

